import { tokenize } from './tokenizer.ts';
import { Parser } from './parser.ts';
import { serialize, getMirrorToken } from './serializer.ts';
import type { ComponentValue, Token, CSSFunction } from './types.ts';
import { unitToBase } from './units.ts';

export class MediaParser {
  /**
   * Parse a media query list string into an array of normalized media queries.
   * Invalid queries are replaced with 'not all'.
   */
  public static parse(mediaText: string): string[] {
    if (!mediaText || mediaText.trim() === '') {
      return [];
    }

    const tokens = tokenize(mediaText);
    const parser = new Parser(tokens);
    const values = parser.parseComponentValues();

    const queries: string[] = [];
    let currentQuery: ComponentValue[] = [];

    for (const val of values) {
      if (val.type === 'comma') {
        queries.push(this.normalizeAndValidate(currentQuery));
        currentQuery = [];
      } else if (val.type === 'whitespace' && currentQuery.length === 0) {
        // Skip leading whitespace
      } else {
        currentQuery.push(val);
      }
    }

    if (currentQuery.length > 0) {
      queries.push(this.normalizeAndValidate(currentQuery));
    }

    return queries;
  }

  private static normalizeAndValidate(values: ComponentValue[]): string {
    const canonical = this.canonicalSerialize(values);
    const tokens = tokenize(canonical);
    const parser = new Parser(tokens);
    const canonicalValues = parser.parseComponentValues();

    const validator = new MediaQueryValidator(canonicalValues);
    if (!validator.validate()) {
      return 'not all';
    }

    return canonical;
  }

  private static canonicalSerialize(values: ComponentValue[]): string {
    let result = '';
    let lastType: string | null = null;

    const filtered = values.filter(v => v.type !== 'whitespace' && v.type !== 'comment');

    for (let i = 0; i < filtered.length; i++) {
      const v = filtered[i];
      let serialized = '';

      if (v.type === 'simple-block') {
        const start = v.associatedToken.value;
        const end = getMirrorToken(start);
        serialized = start + this.canonicalSerialize(v.value as ComponentValue[]) + end;
      } else if (v.type === 'function') {
        const fn = v as CSSFunction;
        serialized = fn.name.toLowerCase() + '(' + this.canonicalSerialize(fn.value as ComponentValue[]) + ')';
      } else if (v.type === 'ident') {
        serialized = v.value.toLowerCase();
      } else if (v.type === 'at-keyword') {
        serialized = '@' + v.value.toLowerCase();
      } else {
        serialized = serialize([v]).trim();
      }

      const isOperator = v.type === 'delim' && (v.value === '>' || v.value === '<' || v.value === '=');
      const lastWasOperator = lastType === 'delim' && (result.endsWith('>') || result.endsWith('<') || result.endsWith('='));

      // Add space between idents or between ident and other things if needed
      if (lastType === 'ident' && (v.type === 'ident' || v.type === 'number' || v.type === 'dimension' || v.type === 'delim' || v.type === 'simple-block')) {
        result += ' ';
      } else if (lastType === 'simple-block' && v.type === 'ident') {
        result += ' ';
      } else if (lastType === 'delim' && v.type === 'ident') {
        if (!result.endsWith(' ')) result += ' ';
      } else if (lastType === 'colon') {
        result += ' ';
      } else if (isOperator && !lastWasOperator) {
        // Add space before operators if not already there and not part of a combined operator
        if (!result.endsWith(' ') && result.length > 0 && !result.endsWith('(')) result += ' ';
      }

      result += serialized;
      
      // Add space after operators if not the first part of a combined operator
      if (isOperator) {
        const next = filtered[i + 1];
        const nextIsOperator = next && next.type === 'delim' && (next.value === '>' || next.value === '<' || next.value === '=');
        if (!nextIsOperator) {
          result += ' ';
        }
      }
      
      lastType = v.type;
    }

    return result.trim();
  }

  private static lowercaseIdents(values: ComponentValue[]): void {
    for (const val of values) {
      if (val.type === 'ident') {
        val.value = val.value.toLowerCase();
      } else if (val.type === 'simple-block' || val.type === 'function') {
        MediaParser.lowercaseIdents(val.value as ComponentValue[]);
      }
    }
  }
}

// mediaqueries-4 #evaluating
type TruthValue = 'TRUE' | 'FALSE' | 'UNKNOWN' | 'MAYBE';

const TruthValue: Record<TruthValue, TruthValue> = {
  TRUE: 'TRUE',
  FALSE: 'FALSE',
  UNKNOWN: 'UNKNOWN',
  MAYBE: 'MAYBE',
};

class MediaQueryValidator {
  private stream: ComponentValue[];
  private pos: number;

  private static readonly KNOWN_FEATURES = new Set([
    'width', 'min-width', 'max-width',
    'height', 'min-height', 'max-height',
    'aspect-ratio', 'min-aspect-ratio', 'max-aspect-ratio',
    'device-width', 'min-device-width', 'max-device-width',
    'device-height', 'min-device-height', 'max-device-height',
    'device-aspect-ratio', 'min-device-aspect-ratio', 'max-device-aspect-ratio',
    'orientation',
    'resolution', 'min-resolution', 'max-resolution',
    'scan',
    'grid',
    'update',
    'overflow-block',
    'overflow-inline',
    'color', 'min-color', 'max-color',
    'color-index', 'min-color-index', 'max-color-index',
    'monochrome', 'min-monochrome', 'max-monochrome',
    'color-gamut',
    'pointer',
    'hover',
    'any-pointer',
    'any-hover',
    'prefers-color-scheme',
    'prefers-reduced-motion',
    'prefers-contrast',
    'forced-colors',
    'dynamic-range'
  ]);

  private static readonly FEATURE_VALUE_TYPES: Record<string, string[]> = {
    'width': ['length'], 'min-width': ['length'], 'max-width': ['length'],
    'height': ['length'], 'min-height': ['length'], 'max-height': ['length'],
    'device-width': ['length'], 'min-device-width': ['length'], 'max-device-width': ['length'],
    'device-height': ['length'], 'min-device-height': ['length'], 'max-device-height': ['length'],
    'aspect-ratio': ['ratio'], 'min-aspect-ratio': ['ratio'], 'max-aspect-ratio': ['ratio'],
    'device-aspect-ratio': ['ratio'], 'min-device-aspect-ratio': ['ratio'], 'max-device-aspect-ratio': ['ratio'],
    'resolution': ['resolution'], 'min-resolution': ['resolution'], 'max-resolution': ['resolution'],
    'orientation': ['ident'],
    'scan': ['ident'],
    'grid': ['integer'],
    'update': ['ident'],
    'overflow-block': ['ident'],
    'overflow-inline': ['ident'],
    'color': ['integer'], 'min-color': ['integer'], 'max-color': ['integer'],
    'color-index': ['integer'], 'min-color-index': ['integer'], 'max-color-index': ['integer'],
    'monochrome': ['integer'], 'min-monochrome': ['integer'], 'max-monochrome': ['integer'],
    'color-gamut': ['ident'],
    'pointer': ['ident'],
    'hover': ['ident'],
    'any-pointer': ['ident'],
    'any-hover': ['ident'],
    'prefers-color-scheme': ['ident'],
    'prefers-reduced-motion': ['ident'],
    'prefers-contrast': ['ident'],
    'forced-colors': ['ident'],
    'dynamic-range': ['ident'],
  };

  private static readonly FEATURE_ALLOWED_IDENTS: Record<string, string[]> = {
    'orientation': ['portrait', 'landscape'],
    'scan': ['interlace', 'progressive'],
    'update': ['none', 'slow', 'fast'],
    'overflow-block': ['none', 'scroll', 'optional-paged', 'paged'],
    'overflow-inline': ['none', 'scroll'],
    'color-gamut': ['srgb', 'p3', 'rec2020'],
    'pointer': ['none', 'coarse', 'fine'],
    'hover': ['none', 'hover'],
    'any-pointer': ['none', 'coarse', 'fine'],
    'any-hover': ['none', 'hover'],
    'prefers-color-scheme': ['light', 'dark'],
    'prefers-reduced-motion': ['no-preference', 'reduce'],
    'prefers-contrast': ['no-preference', 'less', 'more', 'custom'],
    'forced-colors': ['none', 'active'],
    'dynamic-range': ['standard', 'high'],
  };

  private static readonly NON_NEGATIVE_FEATURES = new Set([
    'width', 'min-width', 'max-width',
    'height', 'min-height', 'max-height',
    'device-width', 'min-device-width', 'max-device-width',
    'device-height', 'min-device-height', 'max-device-height',
    'resolution', 'min-resolution', 'max-resolution',
    'color', 'min-color', 'max-color',
    'color-index', 'min-color-index', 'max-color-index',
    'monochrome', 'min-monochrome', 'max-monochrome',
  ]);

  constructor(stream: ComponentValue[]) {
    this.stream = stream.filter(t => t.type !== 'whitespace' && t.type !== 'comment');
    this.pos = 0;
  }

  private peek(): ComponentValue | undefined {
    return this.stream[this.pos];
  }

  private consume(): ComponentValue | undefined {
    return this.stream[this.pos++];
  }

  private eof(): boolean {
    return this.pos >= this.stream.length;
  }

  private isIdent(val?: string): boolean {
    const t = this.peek();
    if (!t || t.type !== 'ident') return false;
    return val ? t.value.toLowerCase() === val.toLowerCase() : true;
  }
  
  private isSimpleBlock(blockType: string): boolean {
    const t = this.peek();
    return !!t && t.type === 'simple-block' && t.associatedToken.value === blockType;
  }

  public validate(): boolean {
    if (this.stream.length === 0) return false;
    const startPos = this.pos;
    
    // <media-query> = <media-condition>
    //              | [ not | only ]? <media-type> [ and <media-condition-without-or> ]?
    
    let result = this.parseMediaCondition();
    if (result !== null && this.eof()) {
      return result !== TruthValue.UNKNOWN;
    }

    this.pos = startPos;
    
    let isNot = false;
    if (this.isIdent('not')) {
      this.consume();
      isNot = true;
    } else if (this.isIdent('only')) {
      this.consume();
    }
    
    const mediaTypeResult = this.parseMediaType();
    if (mediaTypeResult !== null) {
      let finalResult = mediaTypeResult;
      if (isNot) {
        finalResult = this.evalNot(finalResult);
      }
      
      if (this.isIdent('and')) {
        this.consume();
        const condResult = this.parseMediaConditionWithoutOr();
        if (condResult === null) return false;
        finalResult = this.evalAnd(finalResult, condResult);
      }
      
      if (this.eof()) {
        return finalResult !== TruthValue.UNKNOWN;
      }
    }
    
    return false;
  }

  // mediaqueries-4 #evaluating
  private evalNot(val: TruthValue): TruthValue {
    if (val === TruthValue.TRUE) return TruthValue.FALSE;
    if (val === TruthValue.FALSE) return TruthValue.TRUE;
    if (val === TruthValue.UNKNOWN) return TruthValue.UNKNOWN;
    return TruthValue.MAYBE;
  }

  // mediaqueries-4 #evaluating
  private evalAnd(a: TruthValue, b: TruthValue): TruthValue {
    if (a === TruthValue.FALSE || b === TruthValue.FALSE) return TruthValue.FALSE;
    if (a === TruthValue.TRUE && b === TruthValue.TRUE) return TruthValue.TRUE;
    if (a === TruthValue.MAYBE || b === TruthValue.MAYBE) {
      // If one is FALSE, it's FALSE (handled above).
      // If one is UNKNOWN, and the other is TRUE or MAYBE:
      // Unknown AND True/Maybe -> UNKNOWN (could be false if Unknown is false, or true/false if Unknown is true)
      // Actually, if a is UNKNOWN and b is TRUE, result is UNKNOWN.
      // If a is UNKNOWN and b is MAYBE, result is UNKNOWN (since it's effectively false in boolean context anyway).
      if (a === TruthValue.UNKNOWN || b === TruthValue.UNKNOWN) return TruthValue.UNKNOWN;
      return TruthValue.MAYBE;
    }
    return TruthValue.UNKNOWN;
  }

  // mediaqueries-4 #evaluating
  private evalOr(a: TruthValue, b: TruthValue): TruthValue {
    if (a === TruthValue.TRUE || b === TruthValue.TRUE) return TruthValue.TRUE;
    if (a === TruthValue.FALSE && b === TruthValue.FALSE) return TruthValue.FALSE;
    if (a === TruthValue.MAYBE || b === TruthValue.MAYBE) return TruthValue.MAYBE;
    return TruthValue.UNKNOWN;
  }

  private parseMediaType(): TruthValue | null {
    const t = this.peek();
    if (!t || t.type !== 'ident') return null;
    const v = t.value.toLowerCase();
    if (v === 'not' || v === 'only' || v === 'and' || v === 'or' || v === 'layer') {
      return null;
    }
    this.consume();
    if (v === 'all') return TruthValue.TRUE;
    if (v === 'screen' || v === 'print' || v === 'speech') return TruthValue.MAYBE;
    // Unknown media types are FALSE (they never match), but "not unknown" is TRUE.
    return TruthValue.FALSE;
  }

  private parseMediaCondition(): TruthValue | null {
    const startPos = this.pos;
    if (this.isIdent('not')) {
      this.consume();
      const res = this.parseMediaInParens();
      if (res !== null) return this.evalNot(res);
      this.pos = startPos;
      return null;
    }

    let res = this.parseMediaInParens();
    if (res === null) return null;

    if (this.isIdent('and')) {
      while (this.isIdent('and')) {
        this.consume();
        const next = this.parseMediaInParens();
        if (next === null) return null;
        res = this.evalAnd(res, next);
      }
    } else if (this.isIdent('or')) {
      while (this.isIdent('or')) {
        this.consume();
        const next = this.parseMediaInParens();
        if (next === null) return null;
        res = this.evalOr(res, next);
      }
    }
    return res;
  }

  private parseMediaConditionWithoutOr(): TruthValue | null {
    const startPos = this.pos;
    if (this.isIdent('not')) {
      this.consume();
      const res = this.parseMediaInParens();
      if (res !== null) return this.evalNot(res);
      this.pos = startPos;
      return null;
    }

    let res = this.parseMediaInParens();
    if (res === null) return null;

    while (this.isIdent('and')) {
      this.consume();
      const next = this.parseMediaInParens();
      if (next === null) return null;
      res = this.evalAnd(res, next);
    }
    return res;
  }

  private parseMediaInParens(): TruthValue | null {
    const t = this.peek();
    if (!t) return null;
    
    if (t.type === 'simple-block' && t.associatedToken.value === '(') {
      this.consume();
      const tokens = t.value.filter((v: ComponentValue) => v.type !== 'whitespace' && v.type !== 'comment');
      return this.validateMediaInParens(tokens);
    }
    
    if (t.type === 'function' && Array.isArray(t.value)) {
      this.consume();
      // Functions in media queries are <general-enclosed>
      return TruthValue.UNKNOWN;
    }
    
    // <general-enclosed> = [ ( <any-value>? ) ]
    if (t.type === 'simple-block' && t.associatedToken.value === '(') {
       // Already handled above, but if it didn't match <media-feature> it should be UNKNOWN.
       // However, validateMediaInParens handles that.
    }

    return null;
  }

  private isValidMfValue(tokens: ComponentValue[]): boolean {
    if (tokens.length === 0) return false;
    for (const t of tokens) {
      if (t.type === 'delim' && (t.value === '<' || t.value === '>' || t.value === '=')) {
        return false;
      }
      if (t.type === 'comma') {
        return false;
      }
    }
    return true;
  }

  private isNegative(tokens: ComponentValue[]): boolean {
    for (const t of tokens) {
      if (t.type === 'number' || t.type === 'dimension' || t.type === 'percentage') {
        if (parseFloat(t.value) < 0) return true;
      }
    }
    return false;
  }

  private matchesType(tokens: ComponentValue[], types: string[], featureName: string): boolean {
    if (tokens.length === 0) return false;
    const t = tokens[0];
    if (types.includes('length')) {
      if (t.type === 'dimension') {
        const unit = (t as Token).unit?.toLowerCase();
        if (unit && unitToBase[unit] === 'length') return true;
      }
      if (t.type === 'number' && parseFloat((t as Token).value) === 0) return true;
    }
    if (types.includes('resolution')) {
      if (t.type === 'dimension') {
        const unit = (t as Token).unit?.toLowerCase();
        if (unit && (unitToBase[unit] === 'resolution' || unit === 'x')) return true;
      }
    }
    if (types.includes('ident')) {
      if (t.type === 'ident') {
        const allowed = MediaQueryValidator.FEATURE_ALLOWED_IDENTS[featureName];
        if (allowed) {
          return allowed.includes(t.value.toLowerCase());
        }
        return true;
      }
    }
    if (types.includes('integer')) {
      if (t.type === 'number' && (t as Token).numberType === 'integer') return true;
    }
    if (types.includes('ratio')) {
      if (t.type === 'number') {
        if (tokens.length === 1) return true;
        if (tokens.length === 3 && tokens[1].type === 'delim' && (tokens[1] as Token).value === '/' && tokens[2].type === 'number') return true;
      }
    }
    return false;
  }

  private validateMediaInParens(tokens: ComponentValue[]): TruthValue {
    if (tokens.length === 0) return TruthValue.UNKNOWN;

    const validator = new MediaQueryValidator(tokens);
    const condResult = validator.parseMediaCondition();
    if (condResult !== null && validator.eof()) {
      return condResult;
    }

    if (tokens.length >= 3 && tokens[0].type === 'ident' && tokens[1].type === 'colon') {
      const featureName = tokens[0].value.toLowerCase();
      if (MediaQueryValidator.KNOWN_FEATURES.has(featureName)) {
        const valueTokens = tokens.slice(2);
        if (this.isValidMfValue(valueTokens)) {
          if (MediaQueryValidator.NON_NEGATIVE_FEATURES.has(featureName)) {
            if (this.isNegative(valueTokens)) return TruthValue.UNKNOWN;
          }
          const expectedTypes = MediaQueryValidator.FEATURE_VALUE_TYPES[featureName];
          if (expectedTypes && !this.matchesType(valueTokens, expectedTypes, featureName)) {
            return TruthValue.UNKNOWN;
          }
          return TruthValue.MAYBE;
        }
      } else {
        // Unknown feature name
        return TruthValue.UNKNOWN;
      }
    }

    if (tokens.length === 1 && tokens[0].type === 'ident') {
      const featureName = tokens[0].value.toLowerCase();
      if (MediaQueryValidator.KNOWN_FEATURES.has(featureName)) {
        return TruthValue.MAYBE;
      } else {
        // Unknown feature name
        return TruthValue.UNKNOWN;
      }
    }

    const rangeResult = this.parseRangeContext(tokens);
    if (rangeResult !== null) {
      return rangeResult;
    }

    // Fallback to <general-enclosed>
    return TruthValue.UNKNOWN;
  }

  private parseRangeContext(tokens: ComponentValue[]): TruthValue | null {
    const ops = [];
    let pos = 0;
    while (pos < tokens.length) {
      const opInfo = this.parseOperator(tokens, pos);
      if (opInfo) {
        ops.push({ op: opInfo.op, start: pos, end: opInfo.nextPos });
        pos = opInfo.nextPos;
      } else {
        pos++;
      }
    }

    if (ops.length === 1) {
      const left = tokens.slice(0, ops[0].start);
      const right = tokens.slice(ops[0].end);
      if (left.length === 0 || right.length === 0) return null;
      if (!this.isValidMfValue(left) || !this.isValidMfValue(right)) return null;
      
      const leftIsIdent = left.length === 1 && left[0].type === 'ident';
      const rightIsIdent = right.length === 1 && right[0].type === 'ident';
      
      let featureName: string | null = null;
      if (leftIsIdent) {
        featureName = (left[0] as Token).value.toString().toLowerCase();
      } else if (rightIsIdent) {
        featureName = (right[0] as Token).value.toString().toLowerCase();
      }
      
      if (featureName && MediaQueryValidator.KNOWN_FEATURES.has(featureName)) {
        if (MediaQueryValidator.NON_NEGATIVE_FEATURES.has(featureName)) {
          if (this.isNegative(leftIsIdent ? right : left)) return TruthValue.UNKNOWN;
        }
        return TruthValue.MAYBE;
      }
      
      return null;
    } else if (ops.length === 2) {
      const left = tokens.slice(0, ops[0].start);
      const middle = tokens.slice(ops[0].end, ops[1].start);
      const right = tokens.slice(ops[1].end);
      
      if (left.length === 0 || middle.length === 0 || right.length === 0) return null;
      
      const op1 = ops[0].op;
      const op2 = ops[1].op;
      
      const isLessThanOp = (op: string) => op === '<' || op === '<=';
      const isGreaterThanOp = (op: string) => op === '>' || op === '>=';
      
      if (op1 === '=' || op2 === '=') return null;
      if (isLessThanOp(op1) && !isLessThanOp(op2)) return null;
      if (isGreaterThanOp(op1) && !isGreaterThanOp(op2)) return null;
      
      if (!this.isValidMfValue(left) || !this.isValidMfValue(middle) || !this.isValidMfValue(right)) return null;
      if (middle.length === 1 && middle[0].type === 'ident') {
        const featureName = (middle[0] as Token).value.toString().toLowerCase();
        if (MediaQueryValidator.KNOWN_FEATURES.has(featureName)) {
          if (MediaQueryValidator.NON_NEGATIVE_FEATURES.has(featureName)) {
            if (this.isNegative(left) || this.isNegative(right)) return TruthValue.UNKNOWN;
          }
          return TruthValue.MAYBE;
        }
        return TruthValue.UNKNOWN;
      }
      return null;
    }

    return null;
  }

  private parseOperator(tokens: ComponentValue[], pos: number) {
    if (pos >= tokens.length) return null;
    const t1 = tokens[pos];
    if (t1.type !== 'delim') return null;
    if (t1.value === '=') return { op: '=', nextPos: pos + 1 };
    if (t1.value === '<' || t1.value === '>') {
      if (pos + 1 < tokens.length && tokens[pos+1].type === 'delim' && tokens[pos+1].value === '=') {
        return { op: t1.value + '=', nextPos: pos + 2 };
      }
      return { op: t1.value, nextPos: pos + 1 };
    }
    return null;
  }
}
