import { tokenize } from './tokenizer.ts';
import { Parser } from './parser.ts';
import type { ComponentValue, Token, SimpleBlock, CSSFunction } from './types.ts';

export interface PropertyDefinition {
  name: string;
  syntax?: string;
  inherits: boolean;
  initialValue?: string;
}

const VALID_COMPONENTS = new Set([
  'length', 'number', 'percentage', 'length-percentage',
  'color', 'image', 'url', 'integer', 'angle', 'time',
  'resolution', 'transform-function', 'transform-list', 'custom-ident'
]);

class SyntaxError extends Error {
  constructor(message: string) {
    super(message);
    this.name = 'SyntaxError';
  }
}

function validateSyntax(syntax: string): boolean {
  const s = syntax.trim();
  if (s === '*') return true;
  const parts = s.split('|').map(p => p.trim());
  for (const part of parts) {
    if (part.startsWith('<') && part.endsWith('>')) {
      let name = part.slice(1, -1);
      if (name.endsWith('+') || name.endsWith('#')) {
        name = name.slice(0, -1);
      }
      if (!VALID_COMPONENTS.has(name)) return false;
    } else if (part.startsWith('<') && (part.endsWith('>') || part.endsWith('>+') || part.endsWith('>#'))) {
      // Handle <type>+ or <type># where the bracket is not at the very end
      let name = '';
      if (part.endsWith('>+')) name = part.slice(1, -2);
      else if (part.endsWith('>#')) name = part.slice(1, -2);
      else name = part.slice(1, -1);
      if (!VALID_COMPONENTS.has(name)) return false;
    } else {
      // Must be a custom ident literal
      if (!/^[a-zA-Z-][a-zA-Z0-9-]*$/.test(part)) return false;
    }
  }
  return true;
}

function matchesSyntax(tokens: ComponentValue[], syntax: string): boolean {
  if (syntax === '*') return true;
  const parts = syntax.split('|').map(s => s.trim());
  
  for (const part of parts) {
    let type = part;
    let multiplier = '';
    if (part.endsWith('+') || part.endsWith('#')) {
      type = part.slice(0, -1);
      multiplier = part.slice(-1);
    }

    if (type.startsWith('<') && type.endsWith('>')) {
      const name = type.slice(1, -1);
      
      const checkItem = (itemTokens: ComponentValue[]) => {
        if (itemTokens.length !== 1) return false;
        const t = itemTokens[0];
        if (name === 'length') return t.type === 'dimension' || (t.type === 'number' && parseFloat((t as Token).value) === 0);
        if (name === 'number') return t.type === 'number';
        if (name === 'percentage') return t.type === 'percentage';
        if (name === 'length-percentage') return t.type === 'dimension' || t.type === 'percentage' || (t.type === 'number' && parseFloat((t as Token).value) === 0);
        if (name === 'integer') return t.type === 'number' && (t as Token).numberType === 'integer';
        if (name === 'angle') return t.type === 'dimension' && ['deg', 'grad', 'rad', 'turn'].includes((t as Token).unit?.toLowerCase() || '');
        if (name === 'time') return t.type === 'dimension' && ['s', 'ms'].includes((t as Token).unit?.toLowerCase() || '');
        if (name === 'resolution') return t.type === 'dimension' && ['dpi', 'dpcm', 'dppx', 'x'].includes((t as Token).unit?.toLowerCase() || '');
        if (name === 'color') return t.type === 'ident' || t.type === 'function' || (t.type === 'hash');
        if (name === 'url') return t.type === 'url' || (t.type === 'function' && (t as CSSFunction).name === 'url');
        if (name === 'image') return t.type === 'url' || t.type === 'function';
        if (name === 'custom-ident') return t.type === 'ident';
        return true;
      };

      if (multiplier === '#') {
        const items: ComponentValue[][] = [[]];
        for (const t of tokens) {
          if (t.type === 'comma') items.push([]);
          else items[items.length - 1].push(t);
        }
        if (items.every(item => checkItem(item))) return true;
      } else if (multiplier === '+') {
        if (tokens.every(t => checkItem([t]))) return true;
      } else {
        if (checkItem(tokens)) return true;
      }
    } else {
      // Ident literal
      if (tokens.length === 1 && tokens[0].type === 'ident' && (tokens[0] as Token).value.toString().toLowerCase() === type.toLowerCase()) return true;
    }
  }
  return false;
}

function isComputationallyIndependent(tokens: ComponentValue[]): boolean {
  for (const t of tokens) {
    if (t.type === 'function') {
      const name = (t as CSSFunction).name.toLowerCase();
      if (['var', 'env', 'attr'].includes(name)) return false;
      if (!isComputationallyIndependent((t as CSSFunction).value)) return false;
    }
    if (t.type === 'dimension') {
      const unit = (t as Token).unit?.toLowerCase();
      if (unit && !['px', 'cm', 'mm', 'in', 'pt', 'pc', 'deg', 'grad', 'rad', 'turn', 's', 'ms', 'dpi', 'dpcm', 'dppx', 'x'].includes(unit)) {
        return false;
      }
    }
    if (t.type === 'ident' && (t as Token).value.toString().toLowerCase() === 'currentcolor') return false;
    if (t.type === 'simple-block') {
      if (!isComputationallyIndependent((t as SimpleBlock).value)) return false;
    }
  }
  return true;
}

const registry = new Map<string, PropertyDefinition>();

export const PropertyRegistry = {
  validate(definition: PropertyDefinition) {
    if (!definition.name.startsWith('--')) {
      throw new SyntaxError('Property name must start with "--"');
    }
    
    const syntax = definition.syntax || '*';
    if (!validateSyntax(syntax)) {
      throw new SyntaxError(`Invalid syntax string: ${syntax}`);
    }

    if (syntax !== '*' && definition.initialValue === undefined) {
      throw new SyntaxError('initialValue is required for non-universal syntax');
    }

    if (definition.initialValue !== undefined) {
      const tokens = tokenize(definition.initialValue).filter(t => t.type !== 'whitespace');
      const parser = new Parser(tokens);
      const values = parser.parseComponentValues();
      
      if (!isComputationallyIndependent(values)) {
        throw new SyntaxError(`initialValue is not computationally independent: ${definition.initialValue}`);
      }
      
      if (syntax !== '*' && !matchesSyntax(values, syntax)) {
        throw new SyntaxError(`initialValue "${definition.initialValue}" does not match syntax "${syntax}"`);
      }
    }
  },

  register(definition: PropertyDefinition) {
    this.validate(definition);
    registry.set(definition.name, definition);
  },
  get(name: string): PropertyDefinition | undefined {
    return registry.get(name);
  },
  clear() {
    registry.clear();
  }
};
